 */
public void removeFromTreeEdgeList() {
    if (prev != null) {
        prev.next = next;
    }
    if (next != null) {
        next.prev = prev;
    }
    if (edgeList != null && edgeList.contains(this)) {
        edgeList.remove(this);
    }
    // Reset references
    prev = null;
    next = null;
    edgeList = null;
}

