    if (s == null || s.isEmpty()) {
        return "";
    }
    try {
        byte[] decodedBytes = Base64.getDecoder().decode(s);
        return new String(decodedBytes);
    } catch (IllegalArgumentException e) {
        // Return empty string if input is not valid base64
        return "";
    }
}

